                !(obj instanceof Map || obj instanceof List || 
                  obj instanceof String || obj instanceof Double || 
                  obj instanceof Boolean)) {
                throw new IllegalArgumentException("unsupported object");
            }
            return obj;
        } catch (Exception e) {
            if (e instanceof IllegalArgumentException) {
                throw (IllegalArgumentException)e;
            }
            throw new IllegalArgumentException("invalid json", e);
        }
    }

    // -------------------- custom JSON parser (only primitives, objects, arrays) --------------------
    private static void skipWhitespace(String s, int[] idx) {
        while (idx[0] < s.length()) {
            char c = s.charAt(idx[0]);
            if (c == ' ' || c == '\t' || c == '\n' || c == '\r') {
                idx[0]++;
            } else {
                break;
            }
        }
    }

    private static Object parseValue(String s, int[] idx) {
        skipWhitespace(s, idx);
        if (idx[0] >= s.length()) {
            throw new IllegalArgumentException("unexpected end of json");
        }
        char c = s.charAt(idx[0]);
        if (c == '"') {
            return parseString(s, idx);
        } else if (c == '{') {
            return parseObject(s, idx);
        } else if (c == '[') {
            return parseArray(s, idx);
        } else if (c == 't' || c == 'f') {
            return parseBoolean(s, idx);
        } else if (c == 'n') {
            return parseNull(s, idx);
        } else {
            return parseNumber(s, idx);
        }
    }

    private static String parseString(String s, int[] idx) {
        if (s.charAt(idx[0]) != '"') {
            throw new IllegalArgumentException("expected '\"'");
        }
        idx[0]++; // skip opening "
        StringBuilder sb = new StringBuilder();
        while (idx[0] < s.length()) {
            char c = s.charAt(idx[0]);
            if (c == '"') {
                idx[0]++; // skip closing "
                return sb.toString();
            } else if (c == '\\') {
                idx[0]++; // skip backslash
                if (idx[0] >= s.length()) {
                    throw new IllegalArgumentException("unexpected end of string escape");
                }
                char esc = s.charAt(idx[0]);
                switch (esc) {
                    case '"': sb.append('"'); break;
                    case '\\': sb.append('\\'); break;
                    case '/': sb.append('/'); break;
                    case 'b': sb.append('\b'); break;
                    case 'f': sb.append('\f'); break;
                    case 'n': sb.append('\n'); break;
                    case 'r': sb.append('\r'); break;
                    case 't': sb.append('\t'); break;
                    case 'u': 
                        // handle unicode escape uXXXX
                        if (idx[0] + 4 >= s.length()) {
                            throw new IllegalArgumentException("invalid unicode escape");
                        }
                        String hex = s.substring(idx[0] + 1, idx[0] + 5);
                        try {
                            sb.append((char) Integer.parseInt(hex, 16));
                        } catch (NumberFormatException e) {
                            throw new IllegalArgumentException("invalid unicode escape: " + hex);
                        }
                        idx[0] += 4; // skip 4 hex digits, will increment below
                        break;
                    default:
                        throw new IllegalArgumentException("invalid escape character: \\" + esc);
                }
                idx[0]++;
            } else {
                sb.append(c);
                idx[0]++;
            }
        }
        throw new IllegalArgumentException("unterminated string");
    }

    private static Double parseNumber(String s, int[] idx) {
        int start = idx[0];
        if (s.charAt(start) == '-') {
            idx[0]++;
        }
        if (idx[0] >= s.length() || !Character.isDigit(s.charAt(idx[0]))) {
            throw new IllegalArgumentException("invalid number");
        }
        while (idx[0] < s.length() && Character.isDigit(s.charAt(idx[0]))) {
            idx[0]++;
        }
        if (idx[0] < s.length() && s.charAt(idx[0]) == '.') {
            idx[0]++;
            if (idx[0] >= s.length() || !Character.isDigit(s.charAt(idx[0]))) {
                throw new IllegalArgumentException("invalid number: decimal point without digits");
            }
            while (idx[0] < s.length() && Character.isDigit(s.charAt(idx[0]))) {
                idx[0]++;
            }
        }
        if (idx[0] < s.length() && (s.charAt(idx[0]) == 'e' || s.charAt(idx[0]) == 'E')) {
            idx[0]++;
            if (idx[0] < s.length() && (s.charAt(idx[0]) == '+' || s.charAt(idx[0]) == '-')) {
                idx[0]++;
            }
            if (idx[0] >= s.length() || !Character.isDigit(s.charAt(idx[0]))) {
                throw new IllegalArgumentException("invalid number: exponent without digits");
            }
            while (idx[0] < s.length() && Character.isDigit(s.charAt(idx[0]))) {
                idx[0]++;
            }
        }
        String numStr = s.substring(start, idx[0]);
        try {
            return Double.parseDouble(numStr);
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException("invalid number: " + numStr);
        }
    }

    private static Boolean parseBoolean(String s, int[] idx) {
        if (s.startsWith("true", idx[0])) {
            idx[0] += 4;
            return Boolean.TRUE;
        } else if (s.startsWith("false", idx[0])) {
            idx[0] += 5;
            return Boolean.FALSE;
        } else {
            throw new IllegalArgumentException("expected true or false");
        }
    }

    private static Object parseNull(String s, int[] idx) {
        if (s.startsWith("null", idx[0])) {
            idx[0] += 4;
            return null;
        } else {
            throw new IllegalArgumentException("expected null");
        }
    }

    private static Map<String, Object> parseObject(String s, int[] idx) {
        if (s.charAt(idx[0]) != '{') {
            throw new IllegalArgumentException("expected '{'");
        }
        idx[0]++; // skip '{'
        Map<String, Object> map = new LinkedHashMap<>();
        skipWhitespace(s, idx);
        if (idx[0] < s.length() && s.charAt(idx[0]) == '}') {
            idx[0]++; // empty object
            return map;
        }
        while (true) {
            skipWhitespace(s, idx);
            if (idx[0] >= s.length()) {
                throw new IllegalArgumentException("unexpected end of object");
            }
            String key = parseString(s, idx);
            skipWhitespace(s, idx);
            if (idx[0] >= s.length() || s.charAt(idx[0]) != ':') {
                throw new IllegalArgumentException("expected ':'");
            }
            idx[0]++; // skip ':'
            skipWhitespace(s, idx);
            Object value = parseValue(s, idx);
            map.put(key, value);
            skipWhitespace(s, idx);
            if (idx[0] >= s.length()) {
                throw new IllegalArgumentException("unexpected end of object");
            }
            char c = s.charAt(idx[0]);
            if (c == '}') {
                idx[0]++;
                return map;
            } else if (c != ',') {
                throw new IllegalArgumentException("expected ',' or '}'");
            }
            idx[0]++; // skip ','
        }
    }

    private static List<Object> parseArray(String s, int[] idx) {
        if (s.charAt(idx[0]) != '[') {
            throw new IllegalArgumentException("expected '['");
        }
        idx[0]++; // skip '['
        List<Object> list = new ArrayList<>();
        skipWhitespace(s, idx);
        if (idx[0] < s.length() && s.charAt(idx[0]) == ']') {
            idx[0]++; // empty array
            return list;
        }
        while (true) {
            skipWhitespace(s, idx);
            Object value = parseValue(s, idx);
            list.add(value);
            skipWhitespace(s, idx);
            if (idx[0] >= s.length()) {
                throw new IllegalArgumentException("unexpected end of array");
            }
            char c = s.charAt(idx[0]);
            if (c == ']') {
                idx[0]++;
                return list;
            } else if (c != ',') {
                throw new IllegalArgumentException("expected ',' or ']'");
            }
            idx[0]++; // skip ','
        }
    }
}

