        Arrays.fill(header, (byte) 0);

        // name (100 bytes)
        byte[] nameBytes = name.getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(nameBytes, 0, header, 0, Math.min(nameBytes.length, 100));

        // mode (8 bytes) – default 0644
        byte[] mode = "0000644".getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(mode, 0, header, 100, 7);
        header[107] = 0;

        // uid / gid (8 bytes each)
        byte[] uid = "0000000".getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(uid, 0, header, 108, 7);
        header[115] = 0;
        byte[] gid = "0000000".getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(gid, 0, header, 116, 7);
        header[123] = 0;

