        String sizeStr = String.format("%011o", data.length);
        byte[] sizeBytes = sizeStr.getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(sizeBytes, 0, header, 124, sizeBytes.length);
        header[136] = 0; // space after size? size field is 12 bytes, null terminated

        // mtime (12 bytes) – default to 0
        byte[] mtime = "00000000000".getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(mtime, 0, header, 136, mtime.length);
        header[148] = 0;

        // chksum (8 bytes) – fill with spaces temporarily
        Arrays.fill(header, 148, 156, (byte) ' ');

        // typeflag (1 byte)
        header[156] = (byte) typeflag;

        // linkname (100 bytes)
        if (linkname != null) {
            byte[] linkBytes = linkname.getBytes(StandardCharsets.US_ASCII);
            System.arraycopy(linkBytes, 0, header, 157, Math.min(linkBytes.length, 100));
        }

        // magic "ustar" + null
        byte[] magic = "ustar\0".getBytes(StandardCharsets.US_ASCII);
        System.arraycopy(magic, 0, header, 257, magic.length);
        // version "00"
        header[263] = '0';
        header[264] = '0';

