import java.util.*;
import java.util.regex.*;

enum TokenType { NUM, OP, LPAREN, RPAREN }

class Token {
    TokenType type;
    String value; // for NUM and OP
    Token(TokenType type, String value) { this.type = type; this.value = value; }
    Token(TokenType type) { this.type = type; this.value = null; }
}

public class Solution {
    private enum BOp { ADD, SUB, MUL, DIV, MOD, FLOORDIV, POW }
    private enum UOp { UADD, USUB }

    private static abstract class Expr {}
    private static class Constant extends Expr { Number val; Constant(Number val) { this.val = val; } }
    private static class BinOp extends Expr { BOp op; Expr left, right; BinOp(BOp op, Expr left, Expr right) { this.op = op; this.left = left; this.right = right; } }
    private static class UnaryOp extends Expr { UOp op; Expr operand; UnaryOp(UOp op, Expr operand) { this.op = op; this.operand = operand; } }

    public static Double evalInput(String inputStr) {
        if (inputStr == null) {
            throw new IllegalArgumentException("inputStr must be a string");
        }
        String s = inputStr.trim();
        if (s.isEmpty()) {
            throw new IllegalArgumentException("empty expression");
        }

        String cleaned = s.replaceAll("\\s+", "");
        if (cleaned.isEmpty()) {
            throw new IllegalArgumentException("empty expression");
        }
        List<Token> tokens = tokenize(cleaned);
        if (tokens.isEmpty()) {
            throw new IllegalArgumentException("invalid syntax");
        }

        Parser parser = new Parser(tokens);
        Expr expr = parser.parseExpression();
        if (parser.pos != tokens.size()) {
            throw new IllegalArgumentException("invalid syntax");
        }

        check(expr);
        return evaluate(expr).doubleValue();
    }

    public static List<Token> tokenize(String cleaned) {
        List<Token> tokens = new ArrayList<>();
        Pattern p = Pattern.compile("(\\d+\\.?\\d*(?:[eE][+-]?\\d+)?|\\.\\d+(?:[eE][+-]?\\d+)?)|(\\*\\*|//|[+\\-*/%()])");
        Matcher m = p.matcher(cleaned);
        while (m.find()) {
            if (m.group(1) != null) {
                tokens.add(new Token(TokenType.NUM, m.group(1)));
            } else if (m.group(2) != null) {
                String op = m.group(2);
                if (op.equals("(")) tokens.add(new Token(TokenType.LPAREN));
                else if (op.equals(")")) tokens.add(new Token(TokenType.RPAREN));
                else tokens.add(new Token(TokenType.OP, op));
            }
        }
        StringBuilder sb = new StringBuilder();
        for (Token t : tokens) {
            if (t.type == TokenType.NUM) sb.append(t.value);
            else if (t.type == TokenType.OP) sb.append(t.value);
            else if (t.type == TokenType.LPAREN) sb.append("(");
            else if (t.type == TokenType.RPAREN) sb.append(")");
        }
        if (!sb.toString().equals(cleaned)) {
            throw new IllegalArgumentException("invalid syntax");
        }
        return tokens;
    }

    private static void check(Expr node) {
        if (node instanceof Constant) {
            if (!(((Constant) node).val instanceof Number)) {
                throw new IllegalArgumentException("only numeric constants");
            }
        } else if (node instanceof BinOp) {
            BinOp b = (BinOp) node;
            if (!(b.op == BOp.ADD || b.op == BOp.SUB || b.op == BOp.MUL || b.op == BOp.DIV ||
                  b.op == BOp.MOD || b.op == BOp.FLOORDIV || b.op == BOp.POW)) {
                throw new IllegalArgumentException("operator not allowed");
            }
            check(b.left);
            check(b.right);
        } else if (node instanceof UnaryOp) {
            UnaryOp u = (UnaryOp) node;
            if (!(u.op == UOp.UADD || u.op == UOp.USUB)) {
                throw new IllegalArgumentException("unary operator not allowed");
            }
            check(u.operand);
        } else {
            throw new IllegalArgumentException("expression not allowed");
        }
    }

    private static Number evaluate(Expr node) {
        if (node instanceof Constant) {
            return ((Constant) node).val;
        } else if (node instanceof BinOp) {
            BinOp b = (BinOp) node;
            Number left = evaluate(b.left);
            Number right = evaluate(b.right);
            return applyBinOp(b.op, left, right);
        } else if (node instanceof UnaryOp) {
            UnaryOp u = (UnaryOp) node;
            Number operand = evaluate(u.operand);
            if (u.op == UOp.UADD) return operand;
            else {
                if (operand instanceof Long) return -((Long) operand);
                else return -((Double) operand);
            }
        }
        throw new RuntimeException("unexpected node type");
    }

    private static Number applyBinOp(BOp op, Number a, Number b) {
        boolean aDouble = a instanceof Double;
        boolean bDouble = b instanceof Double;
        if (op == BOp.ADD) {
            if (aDouble || bDouble) return a.doubleValue() + b.doubleValue();
            else return ((Long) a) + ((Long) b);
        } else if (op == BOp.SUB) {
            if (aDouble || bDouble) return a.doubleValue() - b.doubleValue();
            else return ((Long) a) - ((Long) b);
        } else if (op == BOp.MUL) {
            if (aDouble || bDouble) return a.doubleValue() * b.doubleValue();
            else return ((Long) a) * ((Long) b);
        } else if (op == BOp.DIV) {
            double divisor = b.doubleValue();
            if (divisor == 0.0) throw new ArithmeticException("division by zero");
            return a.doubleValue() / divisor;
        } else if (op == BOp.MOD) {
            if (b.doubleValue() == 0.0) throw new ArithmeticException("division by zero");
            if (aDouble || bDouble) {
                double aVal = a.doubleValue();
                double bVal = b.doubleValue();
