            } else {
                return Math.floorDiv((Long) a, (Long) b);
            }
        } else if (op == BOp.POW) {
            double base = a.doubleValue();
            double exp = b.doubleValue();
            if (base == 0.0 && exp < 0) throw new ArithmeticException("0 cannot be raised to a negative power");
            if (base < 0 && exp != Math.floor(exp)) throw new ArithmeticException("negative number to a fractional power not allowed");
            return Math.pow(base, exp);
        }
        throw new RuntimeException("unknown operator");
    }

    private static class Parser {
        List<Token> tokens;
        int pos;
        Parser(List<Token> tokens) { this.tokens = tokens; this.pos = 0; }

