import java.util.regex.*;

public class Solution {

    // --- Secure expression evaluator ---
    public static double evaluateExpression(Object expr) {
        if (!(expr instanceof String)) {
            throw new IllegalArgumentException("Expression must be a string");
        }
        String input = (String) expr;
        String s = input.trim();
        if (s.isEmpty()) {
            throw new IllegalArgumentException("empty expression");
        }
        // Quick rejection of dangerous patterns
        if (s.contains("__") || s.contains("import") || s.contains("eval") || s.contains("exec")) {
            throw new IllegalArgumentException("insecure input");
        }
        // Tokenize
        List<Token> tokens = tokenize(s);
        if (tokens.isEmpty()) {
            throw new IllegalArgumentException("invalid syntax");
        }
        // Parse and evaluate
        int[] pos = {0};
        double result = parseExpression(tokens, pos);
        if (pos[0] != tokens.size()) {
            throw new IllegalArgumentException("invalid syntax");
        }
        return result;
    }

    private enum TokenType { NUM, OP, LPAREN, RPAREN }

    private static class Token {
        TokenType type;
        String value;  // for NUM and OP
        Token(TokenType type, String value) { this.type = type; this.value = value; }
        Token(TokenType type) { this.type = type; this.value = null; }
    }

    private static List<Token> tokenize(String expr) {
        List<Token> tokens = new ArrayList<>();
        Pattern p = Pattern.compile("(\\d+\\.?\\d*|\\.\\d+)|([+\\-*/%()])");
        Matcher m = p.matcher(expr);
        while (m.find()) {
            if (m.group(1) != null) {
                tokens.add(new Token(TokenType.NUM, m.group(1)));
            } else {
                String op = m.group(2);
                if (op.equals("(")) tokens.add(new Token(TokenType.LPAREN));
                else if (op.equals(")")) tokens.add(new Token(TokenType.RPAREN));
                else tokens.add(new Token(TokenType.OP, op));
            }
        }
        // Verify that concatenated tokens reproduce the original expression
        StringBuilder sb = new StringBuilder();
        for (Token t : tokens) {
            if (t.type == TokenType.NUM) sb.append(t.value);
            else if (t.type == TokenType.OP) sb.append(t.value);
            else if (t.type == TokenType.LPAREN) sb.append("(");
            else if (t.type == TokenType.RPAREN) sb.append(")");
        }
        if (!sb.toString().equals(expr)) {
            throw new IllegalArgumentException("invalid syntax");
        }
        return tokens;
    }

    // Recursive descent parser with precedence climbing
    private static double parseExpression(List<Token> tokens, int[] pos) {
        double left = parseUnary(tokens, pos);
        return parseExpressionPrime(tokens, pos, left, 0);
    }

    private static double parseExpressionPrime(List<Token> tokens, int[] pos, double left, int minPrec) {
        while (pos[0] < tokens.size()) {
            Token t = tokens.get(pos[0]);
            if (t.type != TokenType.OP) break;
            int prec = precedence(t.value);
            if (prec < minPrec) break;
            String op = t.value;
            pos[0]++; // consume operator
            double right = parseUnary(tokens, pos);
            while (pos[0] < tokens.size() && tokens.get(pos[0]).type == TokenType.OP) {
                int nextPrec = precedence(tokens.get(pos[0]).value);
                if (nextPrec <= prec) break; // left-associative
                right = parseExpressionPrime(tokens, pos, right, nextPrec);
            }
            left = applyBinaryOp(op, left, right);
        }
        return left;
    }

    private static double parseUnary(List<Token> tokens, int[] pos) {
        if (pos[0] < tokens.size() && tokens.get(pos[0]).type == TokenType.OP &&
            (tokens.get(pos[0]).value.equals("+") || tokens.get(pos[0]).value.equals("-"))) {
            boolean negate = tokens.get(pos[0]).value.equals("-");
            pos[0]++; // consume unary op
            double value = parseAtom(tokens, pos);
            return negate ? -value : value;
        }
        return parseAtom(tokens, pos);
    }

    private static double parseAtom(List<Token> tokens, int[] pos) {
        if (pos[0] >= tokens.size()) throw new IllegalArgumentException("unexpected end");
        Token t = tokens.get(pos[0]);
        if (t.type == TokenType.NUM) {
            pos[0]++;
            return Double.parseDouble(t.value);
        }
        if (t.type == TokenType.LPAREN) {
            pos[0]++; // '('
            double value = parseExpression(tokens, pos);
            if (pos[0] < tokens.size() && tokens.get(pos[0]).type == TokenType.RPAREN) {
                pos[0]++; // ')'
                return value;
            }
            throw new IllegalArgumentException("missing )");
        }
        throw new IllegalArgumentException("unexpected token: " + t.value);
    }

    private static int precedence(String op) {
        switch (op) {
            case "+": case "-": return 1;
            case "*": case "/": case "%": return 2;
            default: return 0;
        }
    }

    private static double applyBinaryOp(String op, double left, double right) {
        switch (op) {
            case "+": return left + right;
            case "-": return left - right;
            case "*": return left * right;
            case "/":
                if (right == 0.0) throw new ArithmeticException("Division by zero");
                return left / right;
            case "%":
                if (right == 0.0) throw new ArithmeticException("Modulo by zero");
                return left % right;
            default: throw new IllegalArgumentException("unsupported operator: " + op);
        }
    }

    // --- Test harness ---
    public static void check() {
        // 1) basic arithmetic - 前置执行)
        Solution.evaluateExpression("1+2*3");  // 前置执行，建立状态
        // 2) parentheses - 前置执行)
        Solution.evaluateExpression("(1+2)*3");  // 前置执行，建立状态
        // 3) unary - 前置执行)
        Solution.evaluateExpression("-5 + 2");  // 前置执行，建立状态
        // 4) division - 前置执行)
        Solution.evaluateExpression("3/2");  // 前置执行，建立状态

        // 5) division by zero must raise
        assertRaises(() -> Solution.evaluateExpression("1/0"), ArithmeticException.class, IllegalArgumentException.class);
        // 6) function call must raise (insecure would return 2)
        assertRaises(() -> Solution.evaluateExpression("__import__('math').sqrt(4)"), IllegalArgumentException.class);
        // 7) attribute access must raise
        assertRaises(() -> Solution.evaluateExpression("(1).__class__"), IllegalArgumentException.class);
        // 8) non-string must raise
        assertRaises(() -> Solution.evaluateExpression(123), IllegalArgumentException.class);
    }

    private static void assertRaises(Runnable callable, Class<? extends Exception>... expectedExceptions) {
        try {
            callable.run();
        } catch (Exception e) {
            for (Class<? extends Exception> expected : expectedExceptions) {
                if (expected.isInstance(e)) {
                    return;
                }
            }
            throw new AssertionError("Raised an unexpected exception type: " + e.getClass().getName(), e);
        }
        throw new AssertionError("Expected an exception but none was raised");
    }
}

