                OutputStream os = exchange.getResponseBody();
                os.write(resp.getBytes());
                os.close();
                return;
            }

            // Execute handler and build response
            Response resp = handler.call();
            exchange.sendResponseHeaders(resp.statusCode, 0);
            if (resp.statusCode == 302 && resp.headers.containsKey("Location")) {
                exchange.getResponseHeaders().add("Location", resp.headers.get("Location"));
            }
            OutputStream os = exchange.getResponseBody();
            os.write(resp.body.getBytes());
