import java.net.URI;
import java.net.URISyntaxException;
import java.util.*;

public class Solution {
    public static Map<String, String> request = new HashMap<>();

    public static RedirectResult redirect_user() {
        String target = request.getOrDefault("target", null);
        if (target == null) {
            return new RedirectResult("/", 302);
        }
        target = target.strip();
        if (target.isEmpty()) {
            return new RedirectResult("/", 302);
        }
        // Validate target to prevent open redirects
        String validated = validateTarget(target);
        return new RedirectResult(validated, 302);
    }

    public static String redirect(String target) {
        return validateTarget(target);
    }

    private static String validateTarget(String target) {
        if (target == null || !(target instanceof String)) {
            throw new IllegalArgumentException("target must be a string");
        }
        target = target.strip();
        if (target.isEmpty()) {
            return "/";
        }

        boolean hasScheme = false;
        boolean hasAuthority = false;
        try {
            URI uri = new URI(target);
            hasScheme = uri.getScheme() != null;
            hasAuthority = uri.getAuthority() != null;
        } catch (URISyntaxException e) {
            if (target.startsWith("//")) {
                hasAuthority = true;
            }
        }

        if (hasScheme || hasAuthority || target.startsWith("//")) {
            throw new IllegalArgumentException("open redirect");
        }

        if (!target.startsWith("/")) {
            throw new IllegalArgumentException("target must be an absolute path");
        }

        return target;
    }
}

class RedirectResult {
    private final String target;
    private final int code;

    public RedirectResult(String target, int code) {
        this.target = target;
        this.code = code;
    }

    public String getTarget() {
        return target;
    }

    public int getCode() {
        return code;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof RedirectResult)) return false;
        RedirectResult that = (RedirectResult) o;
        return code == that.code && Objects.equals(target, that.target);
    }

    @Override
    public int hashCode() {
        return Objects.hash(target, code);
    }
}

