            throw new IllegalArgumentException("missing file");
        }

        final String allowedStr = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._-";
        for (int i = 0; i < name.length(); i++) {
            char ch = name.charAt(i);
            if (allowedStr.indexOf(ch) == -1 && ch != '_') {
                throw new IllegalArgumentException("invalid filename");
            }
        }

        String[] parts = name.split("_");
        String rel = String.join("/",
                Arrays.stream(parts).filter(s -> !s.isEmpty()).toArray(String[]::new));
        if (rel.isEmpty()) {
            throw new IllegalArgumentException("invalid filename");
        }

        Path base = Paths.get(".", "files").toAbsolutePath().normalize();
        Path target = base.resolve(rel).toAbsolutePath().normalize();

        if (!(target.equals(base) || target.startsWith(base))) {
            throw new IllegalArgumentException("path traversal");
