import java.security.SecureRandom;
import java.security.InvalidKeyException;
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;

public class Solution {

    public static byte[] getHash(Object password) {
        if (!(password instanceof byte[])) {
            throw new IllegalArgumentException("password must be bytes");
        }
        byte[] pwd = (byte[]) password;
        if (pwd.length == 0) {
            throw new IllegalArgumentException("empty password");
        }

        // Generate random 16-byte salt
        SecureRandom random = new SecureRandom();
        byte[] salt = new byte[16];
        random.nextBytes(salt);

        // Derive 32-byte key using PBKDF2-HMAC-SHA256 with 100000 iterations
        byte[] dk = pbkdf2HmacSha256(pwd, salt, 100000, 32);

        // Concatenate salt and derived key
        byte[] result = new byte[salt.length + dk.length];
        System.arraycopy(salt, 0, result, 0, salt.length);
        System.arraycopy(dk, 0, result, salt.length, dk.length);
        return result;
    }

    /**
     * PBKDF2 (Password-Based Key Derivation Function 2) with HMAC-SHA256.
     *
     * @param password   the password bytes
     * @param salt       the salt
     * @param iterations iteration count (c)
     * @param dkLen      desired length of derived key in bytes
     * @return derived key
     */
    private static byte[] pbkdf2HmacSha256(byte[] password, byte[] salt, int iterations, int dkLen) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(new SecretKeySpec(password, "HmacSHA256"));
            int hLen = mac.getMacLength(); // 32 for SHA-256
            // Number of blocks needed
            int l = (int) Math.ceil((double) dkLen / hLen);
            // Buffer for all derived blocks (with possible excess)
            byte[] derived = new byte[l * hLen];

            byte[] block;
            for (int i = 1; i <= l; i++) {
                // Compute U_1 = PRF(password, salt || INT_32_BE(i))
                byte[] ibytes = intToBigEndian(i);
                byte[] inputU1 = new byte[salt.length + ibytes.length];
                System.arraycopy(salt, 0, inputU1, 0, salt.length);
                System.arraycopy(ibytes, 0, inputU1, salt.length, ibytes.length);
                byte[] u = mac.doFinal(inputU1);
                // U_1 used as start for T_i (XOR accumulator)
                block = u.clone();

                // Subsequent U_j = PRF(password, U_{j-1})
                for (int j = 2; j <= iterations; j++) {
                    u = mac.doFinal(u);
                    // XOR the new U into block
                    for (int k = 0; k < hLen; k++) {
                        block[k] ^= u[k];
                    }
                }

                // Copy the computed T_i into the derivied buffer at position (i-1)*hLen
                System.arraycopy(block, 0, derived, (i - 1) * hLen, hLen);
            }

            // Trim to exact dkLen
            byte[] result = new byte[dkLen];
            System.arraycopy(derived, 0, result, 0, dkLen);
            return result;
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("HmacSHA256 algorithm not available", e);
        } catch (InvalidKeyException e) {
            throw new RuntimeException("Invalid key for HmacSHA256", e);
        }
    }

    /**
     * Converts an integer to a 4-byte big-endian representation (as used in PBKDF2).
     */
    private static byte[] intToBigEndian(int value) {
        byte[] bytes = new byte[4];
        bytes[0] = (byte) ((value >>> 24) & 0xFF);
        bytes[1] = (byte) ((value >>> 16) & 0xFF);
        bytes[2] = (byte) ((value >>> 8) & 0xFF);
        bytes[3] = (byte) (value & 0xFF);
        return bytes;
    }
